const express = require('express');
const session = require('express-session');
const axios = require('axios');
const jwt = require('jsonwebtoken');
const { Issuer, generators } = require('openid-client');

const app = express();
const port = 3000;

// Configure session management
app.use(session({
  secret: 'your-secure-secret',
  resave: false,
  saveUninitialized: true,
  cookie: { secure: true, httpOnly: true }
}));

// OpenID Connect configuration
const oidcIssuerUrl = 'https://your-oidc-provider.com';
const clientId = 'your-client-id';
const clientSecret = 'your-client-secret';
const redirectUri = 'http://localhost:3000/callback';

let client;

// Initialize OpenID Connect client
Issuer.discover(oidcIssuerUrl).then(issuer => {
  client = new issuer.Client({
    client_id: clientId,
    client_secret: clientSecret,
    redirect_uris: [redirectUri],
    response_types: ['code']
  });
});

// Start authentication request
app.get('/login', (req, res) => {
  const codeVerifier = generators.codeVerifier();
  const codeChallenge = generators.codeChallenge(codeVerifier);

  req.session.codeVerifier = codeVerifier;

  const authorizationUrl = client.authorizationUrl({
    scope: 'openid email profile',
    code_challenge: codeChallenge,
    code_challenge_method: 'S256'
  });

  res.redirect(authorizationUrl);
});

// Handle callback and exchange code for tokens
app.get('/callback', async (req, res) => {
  const params = client.callbackParams(req);
  const tokenSet = await client.callback(redirectUri, params, { code_verifier: req.session.codeVerifier });

  const idToken = tokenSet.id_token;
  const decoded = jwt.decode(idToken, { complete: true });

  // Validate the ID token
  if (!decoded || !decoded.payload || !decoded.payload.sub) {
    return res.status(400).send('Invalid ID token');
  }

  // Extract user information
  const user = {
    sub: decoded.payload.sub,
    email: decoded.payload.email,
    name: decoded.payload.name
  };

  // Create user session
  req.session.user = user;

  res.send(`Hello, ${user.name}!`);
});

// Logout and destroy session
app.get('/logout', (req, res) => {
  req.session.destroy(err => {
    if (err) {
      return res.status(500).send('Failed to logout');
    }
    res.redirect('/');
  });
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});